const dayjs = require('dayjs');
const Order = require('../model/Order');
const Product = require('../model/Products');
const User = require('../model/User');
const { sendTemplatedEmail } = require('../utils/emailService');

/**
 * Carrier → base tracking URL map.
 * If the admin does not provide a trackingUrl, one is auto-generated by
 * appending the trackingNumber to the carrier's base URL.
 */
const CARRIER_URLS = {
  dhl: 'https://www.dhl.com/en/express/tracking.html?AWB=',
  fedex: 'https://www.fedex.com/fedextrack/?trknbr=',
  ghtk: 'https://khachhang.giaohangtietkiem.vn/tracking/',
  ghn: 'https://donhang.ghn.vn/?order_code=',
  viettelpost: 'https://viettelpost.vn/tra-cuu-hanh-trinh-don?code=',
  ups: 'https://www.ups.com/track?tracknum=',
};

// GET /api/admin/orders
exports.getAllOrders = async (req, res, next) => {
  try {
    const {
      page = 1, limit = 10, status, paymentMethod,
      startDate, endDate, search, sortBy = 'createdAt', sortOrder = 'desc'
    } = req.query;

    const filter = {};
    if (status) filter.status = status;
    if (paymentMethod) filter.paymentMethod = paymentMethod;
    if (startDate || endDate) {
      filter.createdAt = {};
      if (startDate) filter.createdAt.$gte = new Date(startDate);
      if (endDate) filter.createdAt.$lte = new Date(endDate);
    }
    if (search) {
      const invoiceNum = parseInt(search);
      if (!isNaN(invoiceNum)) {
        filter.invoice = invoiceNum;
      } else {
        filter.$or = [
          { name: { $regex: search, $options: 'i' } },
          { email: { $regex: search, $options: 'i' } },
        ];
      }
    }

    const skip = (parseInt(page) - 1) * parseInt(limit);
    const sort = { [sortBy]: sortOrder === 'desc' ? -1 : 1 };

    const [data, totalItems] = await Promise.all([
      Order.find(filter)
        .sort(sort)
        .skip(skip)
        .limit(parseInt(limit))
        .populate('user', 'name email phone address')
        .populate('shipper', 'name email'),
      Order.countDocuments(filter),
    ]);

    res.json({
      success: true,
      data,
      pagination: {
        currentPage: parseInt(page),
        totalPages: Math.ceil(totalItems / parseInt(limit)),
        totalItems,
        itemsPerPage: parseInt(limit),
      },
    });
  } catch (error) {
    next(error);
  }
};

// GET /api/admin/orders/stats
exports.getOrderStats = async (req, res, next) => {
  try {
    const [statusCounts, monthlyStats, paymentStats] = await Promise.all([
      Order.aggregate([
        { $group: { _id: '$status', count: { $sum: 1 }, total: { $sum: '$totalAmount' } } },
      ]),
      Order.aggregate([
        {
          $group: {
            _id: { $dateToString: { format: '%Y-%m', date: '$createdAt' } },
            count: { $sum: 1 },
            total: { $sum: '$totalAmount' },
          },
        },
        { $sort: { _id: -1 } },
        { $limit: 12 },
      ]),
      Order.aggregate([
        { $group: { _id: '$paymentMethod', count: { $sum: 1 }, total: { $sum: '$totalAmount' } } },
      ]),
    ]);

    const totalOrders = statusCounts.reduce((sum, s) => sum + s.count, 0);
    const totalRevenue = statusCounts.reduce((sum, s) => sum + s.total, 0);

    res.json({
      success: true,
      data: { totalOrders, totalRevenue, statusCounts, monthlyStats, paymentStats },
    });
  } catch (error) {
    next(error);
  }
};

// GET /api/admin/orders/:id
exports.getOrderById = async (req, res, next) => {
  try {
    const order = await Order.findById(req.params.id)
      .populate('user', 'name email phone address')
      .populate('shipper', 'name email');
    if (!order) {
      return res.status(404).json({ success: false, message: 'Order not found' });
    }
    res.json({ success: true, data: order });
  } catch (error) {
    next(error);
  }
};

// POST /api/admin/orders
exports.createOrder = async (req, res, next) => {
  try {
    const order = new Order(req.body);
    if (!order.status) order.status = 'pending';

    await order.save();

    // Update product quantities and sellCount
    if (order.cart && order.cart.length > 0) {
      for (const item of order.cart) {
        const productId = item.productId || item._id;
        const qty = item.orderQuantity || item.quantity || 1;
        if (productId) {
          await Product.findByIdAndUpdate(productId, {
            $inc: { quantity: -qty, sellCount: qty },
          });
        }
      }
    }

    if (global.io) global.io.emit('order:created', order);

    res.status(201).json({ success: true, data: order, message: 'Order created successfully' });
  } catch (error) {
    next(error);
  }
};

// PATCH /api/admin/orders/:id
exports.updateOrder = async (req, res, next) => {
  try {
    const order = await Order.findByIdAndUpdate(req.params.id, req.body, { new: true, runValidators: true })
      .populate('user', 'name email phone address');
    if (!order) {
      return res.status(404).json({ success: false, message: 'Order not found' });
    }

    if (global.io) global.io.emit('order:updated', order);

    res.json({ success: true, data: order, message: 'Order updated successfully' });
  } catch (error) {
    next(error);
  }
};

// PATCH /api/admin/orders/:id/status
// Accepts: status, trackingNumber, carrier, trackingUrl, estimatedDelivery, note
exports.updateOrderStatus = async (req, res, next) => {
  try {
    const {
      status,
      trackingNumber,
      carrier,
      trackingUrl,
      estimatedDelivery,
      note,
    } = req.body;

    const order = await Order.findById(req.params.id);
    if (!order) {
      return res.status(404).json({ success: false, message: 'Order not found' });
    }

    const previousStatus = order.status;

    // If cancelling, restore product quantities
    if (
      (status === 'cancel' || status === 'cancelled') &&
      previousStatus !== 'cancel' &&
      previousStatus !== 'cancelled'
    ) {
      if (order.cart && order.cart.length > 0) {
        for (const item of order.cart) {
          const productId = item.productId || item._id;
          const qty = item.orderQuantity || item.quantity || 1;
          if (productId) {
            await Product.findByIdAndUpdate(productId, {
              $inc: { quantity: qty, sellCount: -qty },
            });
          }
        }
      }
    }

    // Apply status
    order.status = status;

    // Auto-set shippedAt when transitioning to shipped
    if (status === 'shipped' && previousStatus !== 'shipped') {
      order.shippedAt = new Date();
    }

    // Auto-set deliveredAt when transitioning to delivered
    if (status === 'delivered' && previousStatus !== 'delivered') {
      order.deliveredAt = new Date();
    }

    // Tracking fields
    if (trackingNumber !== undefined) order.trackingNumber = trackingNumber;
    if (carrier !== undefined) order.carrier = carrier;
    if (estimatedDelivery !== undefined) order.estimatedDelivery = new Date(estimatedDelivery);

    // Auto-generate trackingUrl from carrier template if not provided
    if (trackingNumber && carrier && !trackingUrl) {
      const baseUrl = CARRIER_URLS[(carrier || '').toLowerCase()];
      if (baseUrl) {
        order.trackingUrl = `${baseUrl}${trackingNumber}`;
      }
    } else if (trackingUrl !== undefined) {
      order.trackingUrl = trackingUrl;
    }

    // Append to statusHistory
    const historyEntry = {
      status,
      timestamp: new Date(),
      note: note || undefined,
    };

    // updatedBy — req.user may be an Admin or a User depending on auth middleware
    if (req.user && req.user._id) {
      historyEntry.updatedBy = req.user._id;
    }

    order.statusHistory = order.statusHistory || [];
    order.statusHistory.push(historyEntry);

    await order.save();

    if (global.io) global.io.emit('order:updated', order);

    // ── Fire-and-forget email notifications ──────────────────────────────
    const orderRef = order.orderNumber || `#${order.invoice}`;

    if (status === 'shipped') {
      sendTemplatedEmail('order-shipped', order.email, {
        customerName: order.name,
        orderNumber: orderRef,
        trackingNumber: order.trackingNumber || '',
        carrier: order.carrier || '',
        trackingUrl: order.trackingUrl || '',
        estimatedDelivery: order.estimatedDelivery
          ? dayjs(order.estimatedDelivery).format('YYYY-MM-DD')
          : '',
      }).catch((err) => console.error('[email] order-shipped send error:', err.message));
    }

    if (status === 'delivered') {
      sendTemplatedEmail('order-delivered', order.email, {
        customerName: order.name,
        orderNumber: orderRef,
        deliveredDate: dayjs().format('YYYY-MM-DD'),
      }).catch((err) => console.error('[email] order-delivered send error:', err.message));
    }

    if (status === 'cancelled' || status === 'cancel') {
      sendTemplatedEmail('order-cancelled', order.email, {
        customerName: order.name,
        orderNumber: orderRef,
        cancellationReason: note || 'No reason provided',
      }).catch((err) => console.error('[email] order-cancelled send error:', err.message));
    }
    // ─────────────────────────────────────────────────────────────────────

    res.json({ success: true, data: order, message: `Order status updated to ${status}` });
  } catch (error) {
    next(error);
  }
};

// PATCH /api/admin/orders/:id/take
// Allows a shipper (or admin) to claim an order for delivery
exports.takeOrder = async (req, res, next) => {
  try {
    const order = await Order.findById(req.params.id);
    if (!order) {
      return res.status(404).json({ success: false, message: 'Order not found' });
    }

    if (order.shipper) {
      return res.status(400).json({ success: false, message: 'Order has already been taken by another shipper' });
    }

    if (!['pending', 'processing'].includes(order.status)) {
      return res.status(400).json({
        success: false,
        message: `Cannot take an order with status "${order.status}"`,
      });
    }

    order.shipper = req.user._id;
    order.status = 'shipped';
    order.shippedAt = new Date();

    order.statusHistory = order.statusHistory || [];
    order.statusHistory.push({
      status: 'shipped',
      timestamp: new Date(),
      note: `Order taken by shipper ${req.user.name || req.user._id}`,
      updatedBy: req.user._id,
    });

    await order.save();

    // Re-fetch with populated shipper for the response
    const populated = await Order.findById(order._id)
      .populate('shipper', 'name email')
      .populate('user', 'name email phone address');

    if (global.io) global.io.emit('order:updated', populated);

    res.json({ success: true, data: populated, message: 'Order taken successfully' });
  } catch (error) {
    next(error);
  }
};

// DELETE /api/admin/orders/:id
exports.deleteOrder = async (req, res, next) => {
  try {
    const order = await Order.findById(req.params.id);
    if (!order) {
      return res.status(404).json({ success: false, message: 'Order not found' });
    }

    if (['delivered'].includes(order.status)) {
      return res.status(400).json({
        success: false,
        message: 'Cannot delete a delivered order',
      });
    }

    // Restore product quantities if not already cancelled
    if (order.status !== 'cancel' && order.cart && order.cart.length > 0) {
      for (const item of order.cart) {
        const productId = item.productId || item._id;
        const qty = item.orderQuantity || item.quantity || 1;
        if (productId) {
          await Product.findByIdAndUpdate(productId, {
            $inc: { quantity: qty, sellCount: -qty },
          });
        }
      }
    }

    await Order.findByIdAndDelete(req.params.id);

    if (global.io) global.io.emit('order:deleted', { _id: req.params.id });

    res.json({ success: true, message: 'Order deleted successfully' });
  } catch (error) {
    next(error);
  }
};
